select t_b_tool_template.id as tool_template_id, t_b_tool_template.name as tool_template_name, t_b_tool_template.base_id as tool_template_base_id, t_b_tool_template.base_version as tool_template_base_version, t_b_tool_template.source_id as tool_template_source_id, t_b_tool_template.platform as tool_template_platform, t_b_tool_template.entry_point as tool_template_entry_point, t_b_tool_template.enable as tool_template_enable, t_b_tool_template.create_time as tool_template_create_time, t_b_tool_template.update_time as tool_template_update_time, t_b_tool_template.deleted as tool_template_deleted, t_b_tool_template.version as tool_template_version, tbtb.id as tool_base_id, tbtb.name as tool_base_name, t_b_tool_template.base_version as tool_base_base_version from t_b_tool_template left join t_b_tool_base as tbtb on tbtb.deleted = 0 and tbtb.id = t_b_tool_template.base_id
and t_b_tool_template.deleted = 0
